      flex-direction: column;
    }
    .top-row {
      display: flex;
      align-items: center;
      justify-content: space-between;
      margin-bottom: 10px;
    }
    .profile {
      display: flex;
      align-items: center;
      gap: 14px;
    }
    .logo-circle {
      width: 60px;
      height: 60px;
      border-radius: 50%;
      background: #1a1a1a;
      border: 2.5px solid #FFD700;
      display: flex;
      align-items: center;
      justify-content: center;
      overflow: hidden;
      flex-shrink: 0;
    }
