      width: 100%;
      height: 100%;
      object-fit: cover;
    }
    .profile-info {
      display: flex;
      flex-direction: column;
      gap: 2px;
    }
    .name-row {
      display: flex;
      align-items: center;
      gap: 10px;
    }
    .empresa-nome {
      color: #FFFFFF;
      font-size: 28px;
      font-weight: 600;
      letter-spacing: -0.3px;
      font-family: 'Inter', sans-serif;
    }
    .verified {
