      height: 22px;
      background: #1D9BF0;
      border-radius: 50%;
      display: flex;
      align-items: center;
      justify-content: center;
      flex-shrink: 0;
    }
    .verified svg {
      width: 13px;
      height: 13px;
      fill: white;
    }
    .instagram-handle {
      color: #71767B;
      font-size: 16px;
      font-weight: 400;
      font-family: 'Inter', sans-serif;
    }
    .icon-right {
      color: #FFFFFF;
